<?phpnamespace Nemundo\Core\WebRequest;// namespace Nemundo\Web\Http\HttpRequestuse Nemundo\Core\Base\AbstractBaseClass;abstract class AbstractWebRequest extends AbstractBaseClass{    /**     * @var string     */    public $userAgent;    /**     * @var bool     */    public $throwException = false;    /**     * @var bool     */    public $delayRequest = false;    /**     * @var int     */    public $delayInSecond = 1;    /**     * @var bool     */    public $utf8Decode = false;    /**     * @var bool     */    public $followRedirect =true;    abstract public function getUrl($url);    abstract public function postUrl($url, $data);    // downloadFile    abstract public function downloadUrl($url, $destinationFilename);}